INSERT INTO "ecos_knowledge_document" ("id", "title", "content", "doc_type", "tags", "embedding", "created_at", "entity_types") VALUES ('doc_quality_standard', '供应商质量管理规范', '一、质量保证能力：供应商应建立并有效运行质量管理体系，优先选择通过ISO9001认证的供应商；关键物资供应商应通过IATF16949等专项认证。
二、产品检验与验收：首批供货必须全检或加严检验；正常供货按GB/T2828.1标准抽样检验；连续三批检验合格可转为放宽检验；出现一批不合格恢复加严检验。
三、质量问题处理：一般质量问题7个工作日内提交整改报告；重大质量问题暂停采购并启动专项审核；同一问题重复发生的降低供应商评级。
四、质量绩效监控：每月统计供应商的批次合格率、PPM、质量投诉次数等作为评级依据。', NULL, NULL, '[0.00871695, 0.01788457, 0.03286002, -0.01827219, 0.01730178, -0.02578948, -0.06582411, 0.0083651, -0.05288395, -0.00195579, 0.08251555, -0.32377747, -0.06022467, -0.03540441, 0.0035855, -0.02643019, -0.06020036, -0.00296205, 0.02228581, 0.03092256, 0.05313104, -0.03901816, -0.03762176, 0.04497216, -0.02355063, -0.01158074, -0.03947455, -0.00703004, 0.04006955, -0.0063842, -0.00998564, 0.02824341, -0.00137237, 0.01227927, -0.0154154, 0.02643561, -0.04490008, 0.00213565, 0.03559314, -0.01606889, -0.01263965, -0.01399744, -0.00918237, -0.02189896, 0.05972274, 0.00517486, 0.03777236, 0.04435155, 0.0455076, 0.02037514, 0.00068986, -0.01260276, 0.0190438, -0.03307213, -0.01318228, -0.04548112, 0.02099232, 0.01912947, -0.08812787, 0.02950287, 0.0225871, -0.08206854, -0.04976514, 0.0387893, -0.01775661, -0.03263573, 0.04707374, 0.00412596, -0.03899037, 0.02273779, 0.00692445, -0.03147211, -0.03640611, -0.04870278, 0.02367745, -0.02597687, 0.0089005, 0.0331036, 0.00515132, 0.03404425, 0.05229846, 0.01610548, 0.04719552, -0.00135923, 0.01185227, 0.07405724, -0.06032761, 0.02021597, 0.01263751, -0.07341348, -0.09478836, -0.03387946, 0.03922796, 0.02367436, -0.01464936, 0.06642747, -0.02974725, -0.03333132, -0.01373499, 0.08310376, 0.00468465, -0.01880436, 0.00872655, -0.00055917, 0.01396598, 0.04059553, 0.0047084, -0.01876862, -0.03293295, 0.03357256, -0.05021732, -0.03589265, -0.03022525, 0.07270265, -0.00384807, -0.07755495, -0.06228928, -0.01329547, -0.03871758, 0.03156605, 0.02232782, -0.03634586, -0.00949574, -0.10516529, -0.04093353, 0.0656893, -0.00472578, -0.01759162, -0.06025108, -0.04948625, 0.04246418, 0.02880358, -0.03352512, 0.02791906, 0.05335153, 0.01085593, -0.05640867, -0.01711761, -0.03892833, -0.04034681, 0.01297284, 0.02039041, -0.03435472, -0.06201008, 0.01781912, 0.04090538, -0.00037581, -0.00590059, 0.01034284, -0.01805866, 0.01777069, -0.00591492, 0.01425717, 0.03037979, 0.0405799, 0.01714838, -0