INSERT INTO "ecos_knowledge_document" ("id", "title", "content", "doc_type", "tags", "embedding", "created_at", "entity_types") VALUES ('doc_steel_industry', '钢铁行业供应商特殊要求', '针对钢铁行业供应商（如宝钢集团），除通用准入条件外还需满足以下特殊要求：
一、行业资质：须持有工信部颁发的《钢铁行业生产经营许可证》；产品须通过国家强制性产品认证（如适用）。
二、产能与装备：粗钢产能不低于100万吨/年（特钢企业除外）；须配备炉前快速分析、在线探伤等检测设备；须通过能源管理体系认证ISO50001。
三、环保与安全：须持有有效排污许可证排放达标；须通过安全生产标准化三级及以上认证；吨钢综合能耗须符合国家限额标准。
四、供货业绩：近三年须有向大型制造企业或重点工程供货的业绩；须提供至少3份客户评价证明。', NULL, NULL, '[-0.00760225, -0.01151323, 0.0611373, 0.00199488, -0.04396169, 0.00154939, -0.03111248, 0.02188004, -0.03280615, 0.04017453, 0.07721599, -0.35123208, -0.01030015, -0.05174804, 0.01537904, -0.0460906, -0.08237609, 0.02327546, 0.04198572, -0.03852324, 0.0183928, -0.05030842, -0.04964174, 0.00073021, -0.02556266, -0.01827801, -0.01954276, -0.00849927, 0.02100445, -0.02924474, -0.01464202, -0.00445988, 0.01472966, 0.01981031, -0.02657188, -0.0085865, -0.0446358, -0.00035559, 0.01467352, -0.0110395, -0.00659562, 0.01166982, -0.06034355, 0.07573376, -0.02216462, -0.02386429, 0.01477541, 0.08692929, 0.04213649, 0.00402478, -0.00461109, 0.04008943, 0.01265191, -0.09185073, 0.02450969, -0.03833889, 0.01799082, 0.04310771, -0.00966425, -0.01153159, 0.05112722, -0.05367031, -0.03526045, 0.01778547, -0.02486375, -0.06252811, -0.04255551, 0.04910433, -0.01174838, 0.02228561, 0.01174299, -0.0020721, 0.00557074, 0.00069912, 0.00154632, -0.06379496, -0.02832029, 0.00266377, 0.03289774, 0.01239419, 0.08195994, 0.03438027, -0.01551485, 0.00973485, 0.00079725, 0.02305913, -0.02882512, 0.02121231, -0.05504829, -0.05182314, -0.04225124, -0.06369526, 0.01618174, -0.01657637, -0.04656706, 0.04515587, -0.08165312, -0.00290808, 0.04244303, 0.05233533, -0.04712664, -0.02467976, -0.00152181, 0.01441075, -0.02771322, 0.01077283, 0.05786824, -0.0176839, 0.03927334, 0.00685186, 0.0026079, -0.00176815, -0.0458343, 0.03922874, -0.08386105, -0.05388105, -0.03016912, 0.01722469, -0.06707302, 0.05209132, -0.01428223, 0.01185084, -0.07754123, -0.06497086, -0.01175822, 0.03662097, -0.00756162, -0.01031015, -0.032628, -0.05454174, 0.04136099, 0.0090917, -0.04039963, 0.07409489, -0.00833584, -0.04053356, -0.07507891, 0.03461105, -0.0831399, -0.05498519, -0.02554589, 0.03348644, -0.03280364, -0.07419906, 0.029355, 0.04583474, -0.01284434, -0.0008842, 0.02558954, 0.04022549, -0.00534137, -0.02204636, -0.02542683, -0.01186767, 0.04381979, -0.021061