INSERT INTO "ecos_knowledge_document" ("id", "title", "content", "doc_type", "tags", "embedding", "created_at", "entity_types") VALUES ('doc_supplier_access', '供应商准入管理办法', '第一章 总则
第一条 为规范供应商准入管理，确保采购质量，特制定本办法。
第二条 本办法适用于所有向本公司提供物资、工程和服务的供应商。
第二章 准入条件
第三条 供应商应具备以下基本条件：（一）具有独立法人资格，注册资本不低于100万元人民币；（二）具备相关行业许可证和资质证书；（三）近三年无重大质量事故和违法违规记录；（四）具有稳定的生产能力和良好的财务状况。
第四条 供应商准入审查内容包括：1.企业资质审查：营业执照、税务登记证、行业许可证等；2.技术能力评估：生产设备、检测手段、技术团队等；3.质量管理体系：ISO9001认证或其他等效体系认证；4.财务状况评估：近三年财务报表、银行信用等级等；5.业绩与信誉：近三年主要客户、合同履行情况等。
第三章 准入流程
第五条 供应商准入按以下流程执行：（一）供应商提交准入申请及相关资质文件；（二）采购部门初审，5个工作日内完成；（三）质量部门组织现场考察，10个工作日内完成；（四）评审委员会综合评审；（五）总经理审批，审批通过后纳入合格供应商名录。', NULL, NULL, '[0.03549539, 0.03497134, 0.0759085, -0.0167616, 0.01095508, -0.01754679, -0.07936288, -0.00188581, -0.02954411, 0.0121434, 0.06137893, -0.30368713, -0.01674385, 0.00562801, 0.04411215, 0.02051894, -0.0531371, -0.00830116, -0.00562732, -0.01992228, 0.04615859, 0.00700866, -0.06334426, -0.01104138, -0.02483048, -0.03644383, -0.0437522, 0.01767179, 0.05529326, -0.02423619, 0.00352338, -0.00822312, 0.02322721, 0.00017463, -0.04245635, 0.05284814, -0.04496938, -0.03247126, 0.03200666, -0.04603509, -0.00155019, -0.02621252, -0.05429336, 0.05892009, 0.01975737, -0.03292486, 0.04077353, 0.0678369, 0.06475264, 0.01121691, 0.00663861, 0.00178552, 0.02223684, -0.02275678, 0.00994945, -0.06571647, 0.01462629, 0.05742902, -0.05312979, 0.05287825, 0.04154234, -0.06739086, -0.03540737, 0.02056996, 0.00014807, -0.03063081, 0.01642185, 0.00912699, -0.05061229, 0.00531023, 0.02434753, -0.02350414, -0.04803983, -0.04793026, -0.00192028, -0.02043891, 0.02715743, 0.00687533, 0.00979058, 0.04082126, 0.05016472, 0.0675754, 0.05273825, 0.04049669, 0.01273062, 0.07003655, -0.05313214, 0.00659237, -0.02123347, -0.05350421, -0.08742218, -0.06381932, 0.04046061, -0.01162333, -0.01190452, 0.08746888, 0.00052848, 0.01330127, -0.01307781, 0.06891819, -0.03188182, 0.01415615, 0.04315437, 0.00313128, -0.01409023, 0.00446266, 0.04110445, -0.02549786, 0.00173118, 0.01681496, -0.02886809, -0.01791842, -0.00905476, 0.04880622, -0.04733069, -0.04489773, -0.06548722, 0.0042022, -0.07628075, 0.07006574, 0.01610783, -0.02546671, -0.01606178, -0.07864904, -0.03058195, 0.08853208, 0.03076703, -0.01665935, -0.06385452, -0.06714834, 0.03750059, 0.02644617, 0.01063531, 0.03671176, -0.00679265, -0.02832483, -0.04618806, 0.02271776, -0.05163659, -0.01136437, -0.00397978, 0.00381648, -0.04385212, -0.08108228, -0.01813763, 0.05392019, 0.00363205, 0.00151492, 0.02044706, 0.0205854, 0.0