INSERT INTO "ecos_knowledge_document" ("id", "title", "content", "doc_type", "tags", "embedding", "created_at", "entity_types") VALUES ('doc_procurement_compliance', '采购合规指引——供应商资质审查与利益冲突管理', '一、资质审查基本要求：1.所有新供应商必须通过准入审查方可纳入合格供应商名录；2.合格供应商每年进行一次资质复审，复审不合格的暂停采购资格；3.供应商资质文件有效期届满前30日应提醒更新。
二、重点审查事项：（一）主体资格：营业执照经营范围是否涵盖供应品类；（二）行政许可：涉及特种行业的是否持有有效许可证；（三）质量体系：是否通过ISO9001认证；（四）环保合规：是否取得排污许可证；（五）社会责任：是否存在劳动用工违法等不良记录。
三、禁止准入情形：1.提供虚假资质文件或隐瞒重要信息的；2.近三年发生过重大质量事故的；3.被列入失信被执行人名单的；4.与本公司员工存在利益关联关系未经申报的。
四、利益冲突管理：供应商应在准入申请时如实申报关联关系；隐瞒利益冲突的立即取消准入资格。', NULL, NULL, '[0.00684107, 0.00988617, 0.07768083, -0.04106611, -0.01085343, -0.0279879, -0.09891779, 0.01868167, -0.02420788, 0.00014881, 0.0535443, -0.33697173, 0.01038005, 0.01909777, 0.02005378, 0.01406738, -0.06080394, 0.01281845, 0.04565402, -0.00341794, 0.04266948, -0.03650832, -0.0343819, 0.01343884, -0.0174711, -0.02174208, -0.04602408, 0.00695989, 0.04014016, -0.01368616, -0.02849687, -0.01092171, 0.03936834, 0.00764481, -0.03429906, 0.05332787, -0.02365188, -0.03655857, 0.04759549, 0.0306057, 0.00129229, -0.0467577, -0.06332704, 0.02041506, -0.01574673, -0.01380594, 0.0889458, 0.07755148, 0.06129927, 0.07549008, 0.02260344, -0.02487454, 0.03947986, -0.00838246, -0.02197461, -0.07541779, -0.01974436, 0.04977508, -0.06149288, 0.0553421, 0.05339508, -0.09347411, -0.03199868, 0.00096372, -0.02319151, -0.05955025, 0.04513159, -0.03221016, -0.02462848, 0.00055304, -0.02833443, -0.02170364, -0.00458343, -0.01671445, 0.0282546, -0.03137318, -0.00398431, 0.01675382, 0.03387821, 0.03761684, 0.06140652, 0.09062397, 0.06211622, 0.06181879, -0.00145813, 0.07413057, -0.03662438, 0.01489575, -0.03045954, -0.05702694, -0.09226628, -0.03412088, 0.05139303, -0.02895204, -0.04696249, 0.07144336, -0.02948863, -0.03976084, 0.01040577, 0.04898092, -0.00327438, -0.00506272, 0.05410903, -0.02843679, 0.00762759, 0.05469549, 0.04362523, -0.00075637, -0.04055929, -0.01161181, -0.06137551, -0.01634882, -0.04849177, 0.04333175, -0.01671646, -0.05315683, -0.06485818, 0.00038306, -0.02291827, 0.09080297, 0.02522278, -0.0212787, -0.00421111, -0.08523626, -0.04198082, 0.04593282, -0.02500731, -0.0310071, -0.05326592, -0.03713511, 0.02542371, 0.03064832, -0.04367048, 0.00413178, 0.01690155, 0.01968612, -0.02036626, 0.04113322, -0.05388146, -0.03422644, 0.00104678, -0.01403505, -0.03466379, -0.08638656, -0.02063986, 0.01365947, -0.00840169, 0.00374803, 0.04761019, -0.01372716, 0.03592895, -0.01641816, -0.03869071, 0.00436418, 0.03839472, -0.084