INSERT INTO "ecos_knowledge_document" ("id", "title", "content", "doc_type", "tags", "embedding", "created_at", "entity_types") VALUES ('doc_supplier_audit_checklist', '供应商现场审核检查表', '供应商现场审核应覆盖以下检查项目：
一、质量管理体系（30分）：质量方针和目标是否明确、质量手册和程序文件是否完整、内部审核和管理评审是否按时开展、不合格品控制程序是否有效运行。
二、生产过程控制（25分）：生产工艺流程是否规范、关键工序是否有作业指导书、设备维护保养是否到位、生产环境是否符合要求、检验记录是否完整可追溯。
三、采购与供应链管理（15分）：原材料供应商是否经评估和批准、来料检验是否按规定执行、原材料存储和标识是否规范。
四、人力资源（10分）：关键岗位人员是否具备相应资质、员工培训计划是否落实、质量意识教育是否开展。
五、设备与设施（10分）：生产设备和检测设备是否按规定校准、设备台账和维保记录是否齐全。
六、持续改进（10分）：质量目标是否达成、客户投诉是否及时处理并闭环、纠正预防措施是否有效。', NULL, NULL, '[-0.00042286, -0.01623713, 0.08187604, -0.04006006, 0.00152256, 0.02446409, -0.07271136, 0.0303473, 0.00052651, 0.03567194, 0.07886916, -0.32617596, -0.04635046, 0.07469513, 0.01763259, -0.04559396, -0.07901713, -0.03296484, 0.04453013, 0.02555341, 0.05729023, -0.01216294, -0.04981382, 0.0314062, -0.03579421, -0.02265182, -0.04986933, 0.00729486, 0.044501, 0.02495597, -0.01806645, 0.02095803, 0.04131657, -0.05380047, -0.0399607, 0.03129586, -0.02830372, -0.04517671, 0.03396367, -0.01007587, -0.00567317, -0.03072874, -0.03042175, 0.02549859, 0.00310796, 0.00105888, 0.0688042, 0.04764932, 0.08227569, 0.0118856, 0.01750309, -0.03785285, 0.0381123, -0.01714887, 0.01977435, -0.05280445, 0.00923705, 0.05566978, -0.06449417, 0.03375075, 0.03155473, -0.04853663, 0.01858737, 0.01480366, -0.00765823, -0.0634685, 0.01334148, -0.00709601, -0.03257444, 0.02883412, 4.016e-05, 0.02166726, -0.04584581, -0.04094189, 0.01447372, 0.04474035, 0.06695846, 0.04184331, 0.01317332, 0.05469689, 0.03996287, 0.04379991, 0.0376794, 0.01353146, 0.02235054, 0.00636129, -0.03000299, 0.03559121, -0.03741461, -0.01738665, -0.05446524, -0.02979764, 0.01594922, 0.01097988, -0.05947633, 0.08379432, -0.0783048, -0.01648462, -0.03195229, 0.07242966, -0.01736533, 0.01322689, 0.01819214, -0.03604313, 0.01411084, 0.0014562, 0.05078033, -0.01453911, -0.05297228, 0.01881414, -0.08423665, -0.03204419, 0.04147016, 0.06839816, -0.00409408, -0.0651646, -0.05896111, -0.00080757, -0.08112232, 0.02932159, -0.00055488, -0.0184111, -0.01238733, -0.10517097, -0.05905396, 0.06305441, 0.00059675, -0.02394904, -0.07420728, -0.01280415, 0.0577452, 0.0426208, -0.02450226, 0.00359419, 0.05014687, 0.01159514, -0.02412849, -0.00148108, -0.03431726, -0.03075871, 0.02335609, 0.00236592, -0.03415699, -0.05832634, -0.01238608, 0.04512567, 0.01175631, 0.05042821, 0.00570134, -0.01565555, 0.00858665, 0.00014085, -0.00088975, 0.00468761, 0.01149459, -0.03000055, -0.024469