INSERT INTO "ecos_knowledge_document" ("id", "title", "content", "doc_type", "tags", "embedding", "created_at", "entity_types") VALUES ('doc_supplier_exit', '供应商退出管理规程', '一、退出情形：年度评级为D级的；发生重大质量事故造成严重后果的；连续两年评级为C级且未完成整改的；经营状况严重恶化丧失履约能力的；存在严重违法违规行为的。
二、退出流程：采购部门提出退出建议附证明材料；质量部门法务部门联合审核；报总经理审批；向供应商发出书面退出通知；处理未完结订单和质保事宜。
三、退出后管理：退出供应商信息归档保存不少于3年；退出后1年内不接受重新准入申请；严重违规退出的永久禁止准入。', NULL, NULL, '[0.0244438, 0.00544559, 0.05966017, -0.01037543, 0.03633257, -0.02354623, -0.06171034, -0.0011987, 2.62e-05, -0.03335987, 0.06157262, -0.29164988, -0.02770086, 0.02664271, 0.00384663, 0.01157318, -0.02901573, -0.01329273, 0.05988532, 0.0082049, 0.03712776, 0.06380319, 0.0086413, -0.01323908, -0.01300118, -0.02078419, -0.01317589, 0.04579615, 0.03850778, -0.05226114, -0.03081297, -0.01334114, 0.02626115, -0.00567218, 0.01792955, 0.06318463, 0.00520998, -0.0053477, -0.0090418, -0.01847289, -0.05383939, -0.0375494, -0.02071822, -0.01866561, -0.00326316, -0.01787496, 0.07696997, 0.04756038, 0.03035381, 0.06287326, 0.04788692, -0.02329494, 0.0515957, -0.00271055, 0.01262161, -0.11768273, 0.01093909, 0.02718663, -0.05560854, 0.05141116, 0.0445981, -0.04101809, -0.05488767, 0.00996034, -0.0225613, -0.03905685, 0.06331142, 0.03615572, -0.03926599, 0.01482822, -0.00690001, -0.0340349, -0.00346873, -0.03316667, 0.02214995, -0.03835871, 0.01280393, 0.04466236, 0.04027694, 0.01021901, 0.03550785, 0.05397374, 1.224e-05, 0.0229303, -0.00643067, 0.0822456, -0.04845453, 0.01463158, -0.01618444, -0.07498278, -0.0975703, -0.0041975, 0.0424946, -0.01294332, -0.00596734, 0.04466347, -0.05469528, -0.03970192, -0.00591061, 0.06274236, -0.04034035, -0.0299321, 0.01414316, -0.01166787, -0.01457587, 0.00371155, 0.01249012, -0.00728825, -0.05018888, 0.00183536, -0.01148175, -0.00147382, -0.01459726, 0.03446282, -0.00933666, -0.03994898, -0.05921501, 0.02521691, -0.03614153, 0.07052817, 0.02477029, -0.05575844, -0.03344672, -0.06459204, -0.04434153, 0.06037706, -0.01302828, -0.00702507, -0.06029486, -0.02186975, 0.06837098, 0.02827519, -0.03349358, -0.00398821, 0.04816449, 0.00379715, -0.04920458, -0.00179392, -0.03548684, -0.00787388, -0.00771751, 2.49e-05, -0.03609052, -0.09164617, 0.00484651, 0.05302614, -0.01134171, 0.00450375, 0.02072217, -0.01565857, 0.02967768, 0.02872704, -0.01168907, 0.04123216, 0.03656363, -0.010