INSERT INTO "ecos_knowledge_document" ("id", "title", "content", "doc_type", "tags", "embedding", "created_at", "entity_types") VALUES ('doc_supplier_rating', '供应商评级标准', '第一条 为建立科学的供应商评价体系，根据供应商的综合表现进行分级管理，特制定本标准。
第二条 供应商评级分为四个等级：A级（优秀）综合评分≥90分，可优先采购享受快速结算；B级（良好）综合评分75-89分，正常采购；C级（合格）综合评分60-74分，限制采购量需整改；D级（不合格）综合评分<60分，暂停采购资格。
第三条 评级指标权重：产品质量30%、交付能力25%、价格水平20%、服务支持15%、合规经营10%。
第四条 评级周期：年度评估每年12月对所有合格供应商进行年度评级；出现重大质量事故即时降级；C级供应商整改后可申请重新评级。', NULL, NULL, '[-0.00339101, 0.02096505, 0.05533595, -0.00924391, 0.00021976, -0.02651982, -0.06415308, 0.01735494, -0.05428012, 0.0183164, 0.05673893, -0.33345553, -0.04946954, -0.01041982, 0.03797274, -0.00860225, -0.0404219, -0.02225071, 0.0534203, 0.01658018, 0.08876318, -0.0216141, -0.02706137, 0.04174856, 0.01106904, -0.01781891, -0.03413629, -0.01699505, 0.05105729, -0.01385207, -0.0450861, 0.00584671, -0.01020685, 0.02686781, -0.03227769, -0.00617476, -0.0320804, 0.0042225, 0.06240575, -0.01155195, -0.02593083, 0.00069739, -0.02210179, 0.03020899, 0.0271104, -0.0276449, 0.01091246, 0.06528957, 0.03604217, 0.00619424, -0.03275437, -0.01815335, 0.02540164, -0.03482255, 0.02740083, -0.04256496, 0.04302032, 0.00232547, -0.0508495, 0.0400628, 0.02661364, -0.03551911, -0.04765106, 0.00176488, 0.00602953, -0.01496569, 0.05934858, 0.05131391, -0.05338075, 0.03675399, -0.02378267, -0.01145258, -0.02374003, -0.04117014, 0.04243606, -0.0351259, 0.0080386, 0.00329944, -0.01498532, 0.04739573, 0.01438858, -0.00038885, 0.02612397, 0.01614024, -0.01979504, 0.0459273, -0.05589788, -0.03315283, -0.02767942, -0.08232912, -0.06219397, -0.04658794, 0.0210622, 0.01218642, -0.0439886, 0.07468718, -0.04060361, -0.0091584, -0.05048605, 0.03103991, -0.04974669, -0.02270788, 0.00676444, -0.0374043, 0.01652496, 0.03437934, 0.03802951, 0.00187088, -0.00910409, 0.02587864, -0.05534803, 0.03447269, -0.03138473, 0.03571127, -0.00319839, -0.07025611, -0.05455538, 0.0249855, -0.06546019, 0.031742, 0.02224585, -0.01914501, -0.00164491, -0.0888335, -0.10500887, 0.07775343, -0.01112181, -0.02098122, -0.03956681, -0.02689178, 0.03453777, 0.01418044, -0.03943553, 0.0192858, -0.02568007, 0.03274334, -0.02771855, -0.03023644, -0.05543998, -0.02162843, -0.02981992, 0.04580128, -0.04756453, -0.05942068, 0.0229608, 0.05818522, -0.02516057, -0.01368368, 0.01769098, -0.00364049, 0.01324968, 0.02603791, -0.03056762, 0.01778596, 0.01956248, -